using System;

record Point(double X, double Y);

class Program {
    static void Main() {
        var p1 = new Point(1, 2);
        var p2 = new Point(1, 2);
        var p3 = new Point(3, 4);
        Console.WriteLine(p1 == p2); // value equality
        Console.WriteLine(p1 == p3);
        Console.WriteLine(p1.Equals(p2));
    }
}

using System;

record Config(string Host, int Port, bool Debug);

class Program {
    static void Main() {
        var prod = new Config("example.com", 443, false);
        var dev = prod with { Host = "localhost", Debug = true };
        Console.WriteLine(prod);
        Console.WriteLine(dev);
    }
}

using System;

record Person(string Name, int Age);

class Program {
    static void Main() {
        var people = new[] {
            new Person("Alice", 30),
            new Person("Bob", 25),
        };
        foreach (var (name, age) in people) {
            Console.WriteLine($"{name}: {age}");
        }
    }
}

using System;

record Temperature(double Celsius) {
    public double Fahrenheit => Celsius * 9 / 5 + 32;
    public bool IsFreezing => Celsius <= 0;
    public override string ToString() => $"{Celsius}°C / {Fahrenheit:F1}°F";
}

class Program {
    static void Main() {
        var t = new Temperature(100);
        Console.WriteLine(t);
        Console.WriteLine(new Temperature(-5).IsFreezing);
    }
}

using System;

record struct Point2D(float X, float Y) {
    public float Length => MathF.Sqrt(X * X + Y * Y);
}

class Program {
    static void Main() {
        var p = new Point2D(3, 4);
        Console.WriteLine(p);
        Console.WriteLine(p.Length);
        var q = p with { Y = 0 };
        Console.WriteLine(q);
    }
}

using System;

record Shape(string Color);
record Circle(string Color, double Radius) : Shape(Color);
record Square(string Color, double Side) : Shape(Color);

class Program {
    static void Main() {
        Shape[] shapes = {
            new Circle("red", 5),
            new Square("blue", 4)
        };
        foreach (var s in shapes)
            Console.WriteLine(s);
    }
}

using System;
using System.Text.Json;

record UserDto(int Id, string Name, string Email);

class Program {
    static void Main() {
        var user = new UserDto(1, "Alice", "alice@example.com");
        string json = JsonSerializer.Serialize(user);
        Console.WriteLine(json);

        var back = JsonSerializer.Deserialize<UserDto>(json);
        Console.WriteLine(back == user);
    }
}
